def count_digits(n, digit):
    if n == 0:
        return 0
    return (1 if n % 10 == digit else 0) + count_digits(n // 10, digit)

def squared_tuples(L):
    result = []
    for i in range(len(L)):
        result.append((L[i], L[i] ** 2))
    return result

def group_by_grade(d):
    result = {}
    for student, grade in d.items():
        if grade not in result:
            result[grade] = []
        result[grade].append(student)
    return result

def char_freq(s):
    freq = {}
    for c in s:
        freq[c] = freq.get(c, 0) + 1
    most = max(freq, key=lambda c: freq[c])
    return freq, most


