def verschiedenes(x, y, z):
    abs_y = y if y >= 0 else -y
    if x > y and x < z:
        return x + abs_y * z
    elif y > z:
        return x + y + z
    else:
        return z

def positionen(liste, wert):
    result = []
    for i in range(len(liste)):
        if liste[i] == wert:
            result.append(i)
    return result

def largest_factor(n):
    for i in range(n - 1, 0, -1):
        if n % i == 0:
            return i

